const DEFAULTS={owner:"Dhikr-Buddy",repo:"IslamicAPI",ref:"master"};export function rawUrl(n,o={}){const r={...DEFAULTS,...o};return`https://raw.githubusercontent.com/${r.owner}/${r.repo}/${r.ref}/${String(n).replace(/^\/+/,"")}`}export function downloadToClient(n,o){if("undefined"==typeof window)return;const r=document.createElement("a");r.href=n,r.download=o||n.split("/").pop()||"download.mp3",document.body.appendChild(r),r.click(),document.body.removeChild(r)}export function createDeenRawClient(n={}){const o=rawUrl("data/api/index.json",n);async function r(n){const o=await fetch(n);if(!o.ok)throw new Error(`Fetch failed ${o.status}: ${n}`);return o.json()}async function e(n){const e=(await r(o)).files[n];if(!e)throw new Error(`Unknown Deen raw API key: ${n}`);return r(e.url)}return{indexUrl:o,loadIndex:()=>r(o),loadQuran:()=>e("quran"),loadHadith:()=>e("hadith"),loadAudio:()=>e("audio"),loadFonts:()=>e("fonts"),loadHaramain:()=>r(rawUrl("data/audio/normalized/haramain-compilations.json",n)),rawUrl:o=>rawUrl(o,n)}}